{"content":"     1	import { useState, useCallback, useEffect, useMemo, useRef } from "react";
     2	import { useFileStore } from "@/stores/useFileStore";
     3	import { useLocaleStore } from "@/stores/useLocaleStore";
     4	import { getDragData, setDragData } from "@/lib/dragState";
     5	import type { FileEntry } from "@/lib/host";
     6	import { cn, getFileName } from "@/lib/utils";
     7	import { ContextMenu } from "../toolbar/ContextMenu";
     8	import {
     9	  ChevronRight,
    10	  ChevronDown,
    11	  ChevronUp,
    12	  File,
    13	  Folder,
    14	  FolderOpen,
    15	  Image,
    16	  FileText,
    17	  Shapes,
    18	  Star,
    19	  StarOff,
    20	} from "lucide-react";
    21	import { useFavoriteStore } from "@/stores/useFavoriteStore";
    22	import { useCloudSyncStore } from "@/stores/useCloudSyncStore";
    23	import { useShallow } from "zustand/react/shallow";
    24	import { SIDEBAR_SURFACE_CLASSNAME } from "./sidebarSurface";
    25	import {
    26	  useSidebarFileOperations,
    27	  type CreatingState,
    28	} from "./hooks/useSidebarFileOperations";
    29	import { SidebarHeader } from "./SidebarHeader";
    30	import { SidebarQuickActions } from "./SidebarQuickActions";
    31	
    32	interface ContextMenuState {
    33	  x: number;
    34	  y: number;
    35	  entry: FileEntry | null;
    36	  isDirectory: boolean;
    37	}
    38	
    39	interface RootContextMenuState {
    40	  x: number;
    41	  y: number;
    42	}
    43	
    44	export function Sidebar() {
    45	  const { t } = useLocaleStore();
    46	  const { isLoadingTree } = useFileStore(
    47	    useShallow((state) => ({
    48	      isLoadingTree: state.isLoadingTree,
    49	    })),
    50	  );
    51	  const {
    52	    favorites,
    53	    manualOrder,
    54	    favoriteSortMode,
    55	    setFavoriteSortMode,
    56	    moveFavorite,
    57	    toggleFavorite,
    58	    getFavorites,
    59	  } = useFavoriteStore(
    60	    useShallow((state) => ({
    61	      favorites: state.favorites,
    62	      manualOrder: state.manualOrder,
    63	      favoriteSortMode: state.defaultSortMode,
    64	      setFavoriteSortMode: state.setDefaultSortMode,
    65	      moveFavorite: state.moveFavorite,
    66	      toggleFavorite: state.toggleFavorite,
    67	      getFavorites: state.getFavorites,
    68	    })),
    69	  );
    70	  const favoriteEntries = useMemo(
    71	    () => getFavorites(favoriteSortMode),
    72	    [getFavorites, favoriteSortMode, favorites, manualOrder],
    73	  );
    74	
    75	  const rehydrateToken = useCloudSyncStore((s) => s.rehydrateToken);
    76	  // Restore token from OS keychain on app startup
    77	  useEffect(() => {
    78	    rehydrateToken();
    79	  }, [rehydrateToken]);
    80	
    81	  const ops = useSidebarFileOperations();
    82	  const {
    83	    selectedPath,
    84	    setSelectedPath,
    85	    creating,
    86	    createValue,
    87	    setCreateValue,
    88	    renamingPath,
    89	    setRenamingPath,
    90	    renameValue,
    91	    setRenameValue,
    92	    expandedPaths,
    93	    vaultPath,
    94	    fileTree,
    95	    currentFile,
    96	    openFile,
    97	    refreshFileTree,
    98	    moveFileToFolder,
    99	    moveFolderToFolder,
   100	    handleQuickNote,
   101	    handleRename,
   102	    handleStartRootRename,
   103	    handleSelect,
   104	    handlePermanentOpen,
   105	    handleTreeBackgroundClick,
   106	    handleSelectRoot,
   107	    getContextMenuItems,
   108	    getRootContextMenuItems,
   109	    handleOpenFolder,
   110	    handleNewWindow,
   111	    toggleExpanded,
   112	    handleNewFile,
   113	    handleNewDiagram,
   114	    handleNewFolder,
   115	    handleCreateSubmit,
   116	    handleCreateCancel,
   117	    focusTreePath,
   118	  } = ops;
   119	
   120	  // Context menu state
   121	  const [contextMenu, setContextMenu] = useState<ContextMenuState | null>(null);
   122	  const [rootContextMenu, setRootContextMenu] =
   123	    useState<RootContextMenuState | null>(null);
   124	  const [isRootDragOver, setIsRootDragOver] = useState(false);
   125	  const [isFileTreeScrollActive, setIsFileTreeScrollActive] = useState(false);
   126	  const fileTreeScrollFadeTimerRef = useRef<number | null>(null);
   127	
   128	  const handleContextMenu = useCallback(
   129	    (e: React.MouseEvent, entry: FileEntry) => {
   130	      e.preventDefault();
   131	      e.stopPropagation();
   132	      setContextMenu({
   133	        x: e.clientX,
   134	        y: e.clientY,
   135	        entry,
   136	        isDirectory: entry.is_dir,
   137	      });
   138	    },
   139	    [],
   140	  );
   141	
   142	  const handleRootContextMenu = useCallback(
   143	    (e: React.MouseEvent) => {
   144	      if (!vaultPath) return;
   145	      e.preventDefault();
   146	      e.stopPropagation();
   147	      setSelectedPath(vaultPath);
   148	      setRootContextMenu({
   149	        x: e.clientX,
   150	        y: e.clientY,
   151	      });
   152	    },
   153	    [vaultPath, setSelectedPath],
   154	  );
   155	
   156	  const closeContextMenu = useCallback(() => {
   157	    setContextMenu(null);
   158	    setRootContextMenu(null);
   159	  }, []);
   160	
   161	  // Root drop listener
   162	  useEffect(() => {
   163	    const handleRootDrop = async (e: CustomEvent) => {
   164	      if (!isRootDragOver || !vaultPath) return;
   165	      setIsRootDragOver(false);
   166	
   167	      const { sourcePath, isFolder } = e.detail;
   168	      if (!sourcePath) return;
   169	
   170	      const normalize = (p: string) => p.replace(/\\/g, "/");
   171	      const normalizedSource = normalize(sourcePath);
   172	      const normalizedVault = normalize(vaultPath);
   173	      const sourceParent = normalizedSource.substring(
   174	        0,
   175	        normalizedSource.lastIndexOf("/"),
   176	      );
   177	      if (sourceParent === normalizedVault) return;
   178	
   179	      try {
   180	        if (isFolder) {
   181	          await moveFolderToFolder(sourcePath, vaultPath);
   182	        } else {
   183	          await moveFileToFolder(sourcePath, vaultPath);
   184	        }
   185	      } catch {
   186	        // move actions already report failures in useFileStore
   187	      }
   188	    };
   189	
   190	    window.addEventListener(
   191	      "lumina-folder-drop",
   192	      handleRootDrop as unknown as EventListener,
   193	    );
   194	    return () => {
   195	      window.removeEventListener(
   196	        "lumina-folder-drop",
   197	        handleRootDrop as unknown as EventListener,
   198	      );
   199	    };
   200	  }, [isRootDragOver, vaultPath, moveFileToFolder, moveFolderToFolder]);
   201	
   202	  // Sync selectedPath with currentFile
   203	  useEffect(() => {
   204	    if (currentFile) {
   205	      setSelectedPath(currentFile);
   206	    }
   207	  }, [currentFile, setSelectedPath]);
   208	
   209	  // Focus-path event listener
   210	  useEffect(() => {
   211	    const handleFocusPath = (event: Event) => {
   212	      const customEvent = event as CustomEvent<{ path?: string }>;
   213	      const targetPath = customEvent.detail?.path;
   214	      if (!targetPath) return;
   215	      focusTreePath(targetPath);
   216	    };
   217	
   218	    window.addEventListener(
   219	      "lumina-focus-file-tree-path",
   220	      handleFocusPath as EventListener,
   221	    );
   222	    return () => {
   223	      window.removeEventListener(
   224	        "lumina-focus-file-tree-path",
   225	        handleFocusPath as EventListener,
   226	      );
   227	    };
   228	  }, [focusTreePath]);
   229	
   230	  const markFileTreeScrollActive = useCallback(() => {
   231	    setIsFileTreeScrollActive(true);
   232	    if (fileTreeScrollFadeTimerRef.current !== null) {
   233	      window.clearTimeout(fileTreeScrollFadeTimerRef.current);
   234	    }
   235	    fileTreeScrollFadeTimerRef.current = window.setTimeout(() => {
   236	      setIsFileTreeScrollActive(false);
   237	      fileTreeScrollFadeTimerRef.current = null;
   238	    }, 720);
   239	  }, []);
   240	
   241	  useEffect(() => {
   242	    return () => {
   243	      if (fileTreeScrollFadeTimerRef.current !== null) {
   244	        window.clearTimeout(fileTreeScrollFadeTimerRef.current);
   245	      }
   246	    };
   247	  }, []);
   248	
   249	  return (
   250	    <aside className={SIDEBAR_SURFACE_CLASSNAME}>
   251	      {/* Header */}
   252	      <SidebarHeader
   253	        onNewFile={() => handleNewFile()}
   254	        onNewDiagram={() => handleNewDiagram()}
   255	        onNewFolder={() => handleNewFolder()}
   256	        onRefresh={refreshFileTree}
   257	        isLoadingTree={isLoadingTree}
   258	        onOpenFolder={handleOpenFolder}
   259	        onNewWindow={handleNewWindow}
   260	      />
   261	
   262	      {/* Toolbar Zone */}
   263	      <div className="flex flex-col gap-3 py-2 border-b border-border/60">
   264	        {/* Quick Actions */}
   265	        <SidebarQuickActions
   266	          vaultPath={vaultPath}
   267	          onQuickNote={handleQuickNote}
   268	        />
   269	
   270	        {/* Favorites */}
   271	        <div className="px-2">
   272	          <div className="mb-1 flex items-center justify-between gap-2 rounded-ui-sm bg-amber-500/5 px-2 py-1">
   273	            <span className="flex min-w-0 items-center gap-1.5 text-xs font-semibold text-muted-foreground whitespace-nowrap overflow-hidden text-ellipsis">
   274	              <Star className="h-3.5 w-3.5 shrink-0 text-yellow-500" />
   275	              {t.favorites.title}
   276	            </span>
   277	            <div className="flex items-center gap-1">
   278	              <button
   279	                onClick={() => setFavoriteSortMode("manual")}
   280	                className={cn(
   281	                  "px-1.5 py-0.5 text-[10px] rounded border transition-colors whitespace-nowrap",
   282	                  favoriteSortMode === "manual"
   283	                    ? "bg-accent text-foreground border-border"
   284	                    : "text-muted-foreground border-transparent hover:border-border hover:text-foreground",
   285	                )}
   286	                title={t.favorites.sortManual}
   287	              >
   288	                {t.favorites.sortManual}
   289	              </button>
   290	              <button
   291	                onClick={() => setFavoriteSortMode("recentAdded")}
   292	                className={cn(
   293	                  "px-1.5 py-0.5 text-[10px] rounded border transition-colors whitespace-nowrap",
   294	                  favoriteSortMode === "recentAdded"
   295	                    ? "bg-accent text-foreground border-border"
   296	                    : "text-muted-foreground border-transparent hover:border-border hover:text-foreground",
   297	                )}
   298	                title={t.favorites.sortRecentAdded}
   299	              >
   300	                {t.favorites.sortRecentAdded}
   301	              </button>
   302	              <button
   303	                onClick={() => setFavoriteSortMode("recentOpened")}
   304	                className={cn(
   305	                  "px-1.5 py-0.5 text-[10px] rounded border transition-colors whitespace-nowrap",
   306	                  favoriteSortMode === "recentOpened"
   307	                    ? "bg-accent text-foreground border-border"
   308	                    : "text-muted-foreground border-transparent hover:border-border hover:text-foreground",
   309	                )}
   310	                title={t.favorites.sortRecentOpened}
   311	              >
   312	                {t.favorites.sortRecentOpened}
   313	              </button>
   314	            </div>
   315	          </div>
   316	          {favoriteEntries.length === 0 ? (
   317	            <div className="px-2 py-2 text-xs text-muted-foreground">
   318	              {t.favorites.empty}
   319	            </div>
   320	          ) : (
   321	            <div className="space-y-1">
   322	              {favoriteEntries.map((entry, index) => (
   323	                <div
   324	                  key={entry.path}
   325	                  className={cn(
   326	                    "group flex items-center gap-2 px-2 py-1 rounded-ui-md text-xs",
   327	                    currentFile === entry.path
   328	                      ? "bg-accent text-foreground"
   329	                      : "text-muted-foreground hover:bg-accent/60 hover:text-foreground",
   330	                  )}
   331	                >
   332	                  <button
   333	                    onClick={() => openFile(entry.path)}
   334	                    className="flex-1 flex items-center gap-2 text-left truncate"
   335	                    title={entry.path}
   336	                  >
   337	                    <Star className="w-3.5 h-3.5 text-yellow-500" />
   338	                    <span className="truncate">
   339	                      {getFileName(entry.path).replace(/\.md$/i, "")}
   340	                    </span>
   341	                  </button>
   342	                  {favoriteSortMode === "manual" && (
   343	                    <div className="flex items-center gap-0.5 opacity-0 group-hover:opacity-100 transition-opacity">
   344	                      <button
   345	                        onClick={(e) => {
   346	                          e.stopPropagation();
   347	                          moveFavorite(index, index - 1);
   348	                        }}
   349	                        className="p-0.5 rounded-ui-sm hover:bg-accent/60"
   350	                        title={t.favorites.moveUp}
   351	                        disabled={index === 0}
   352	                      >
   353	                        <ChevronUp className="w-3 h-3" />
   354	                      </button>
   355	                      <button
   356	                        onClick={(e) => {
   357	                          e.stopPropagation();
   358	                          moveFavorite(index, index + 1);
   359	                        }}
   360	                        className="p-0.5 rounded-ui-sm hover:bg-accent/60"
   361	                        title={t.favorites.moveDown}
   362	                        disabled={index === favoriteEntries.length - 1}
   363	                      >
   364	                        <ChevronDown className="w-3 h-3" />
   365	                      </button>
   366	                    </div>
   367	                  )}
   368	                  <button
   369	                    onClick={(e) => {
   370	                      e.stopPropagation();
   371	                      toggleFavorite(entry.path);
   372	                    }}
   373	                    className="p-0.5 rounded-ui-sm hover:bg-accent/60 opacity-0 group-hover:opacity-100 transition-opacity"
   374	                    title={t.favorites.remove}
   375	                  >
   376	                    <StarOff className="w-3 h-3" />
   377	                  </button>
   378	                </div>
   379	              ))}
   380	            </div>
   381	          )}
   382	        </div>
   383	      </div>
   384	
   385	      {/* Vault Name - root drop zone */}
   386	      {renamingPath === vaultPath ? (
   387	        <div className="bg-background/35 px-2 py-1.5">
   388	          <input
   389	            type="text"
   390	            value={renameValue}
   391	            onChange={(e) => setRenameValue(e.target.value)}
   392	            onBlur={() => {
   393	              void handleRename();
   394	            }}
   395	            onKeyDown={(e) => {
   396	              if (e.key === "Enter") {
   397	                e.preventDefault();
   398	                void handleRename();
   399	              } else if (e.key === "Escape") {
   400	                setRenamingPath(null);
   401	              }
   402	            }}
   403	            autoFocus
   404	            className="ui-input h-8 w-full border-primary/60 px-2"
   405	          />
   406	        </div>
   407	      ) : (
   408	        <div
   409	          role="button"
   410	          tabIndex={0}
   411	          data-folder-path={vaultPath}
   412	          onClick={handleSelectRoot}
   413	          onContextMenu={handleRootContextMenu}
   414	          onKeyDown={(e) => {
   415	            if (
   416	              (e.key === "Enter" || e.key === "F2") &&
   417	              selectedPath === vaultPath
   418	            ) {
   419	              e.preventDefault();
   420	              handleStartRootRename();
   421	            }
   422	          }}
   423	          onMouseEnter={() => {
   424	            const dragData = getDragData();
   425	            if (dragData?.isDragging) {
   426	              setIsRootDragOver(true);
   427	            }
   428	          }}
   429	          onMouseLeave={() => setIsRootDragOver(false)}
   430	          className={cn(
   431	            "cursor-pointer select-none px-3 py-2 text-sm font-medium truncate bg-background/35 transition-colors hover:bg-background/45",
   432	            isRootDragOver && "bg-primary/15 ring-1 ring-primary/40 ring-inset",
   433	            selectedPath === vaultPath &&
   434	              "bg-primary/10 ring-1 ring-primary/30 ring-inset text-primary",
   435	          )}
   436	        >
   437	          {vaultPath?.split(/[/\\]/).pop() || "Notes"}
   438	        </div>
   439	      )}
   440	
   441	      {/* File Tree */}
   442	      <div
   443	        className={cn(
   444	          "sidebar-file-tree-scroll flex-1 overflow-auto py-2 pr-1",
   445	          isFileTreeScrollActive && "is-scroll-active",
   446	          selectedPath === vaultPath && "ring-1 ring-primary/20 ring-inset",
   447	        )}
   448	        onScroll={markFileTreeScrollActive}
   449	        onClick={handleTreeBackgroundClick}
   450	      >
   451	        {/* Root create input */}
   452	        {creating && creating.parentPath === vaultPath && (
   453	          <CreateInputRow
   454	            type={creating.type}
   455	            value={createValue}
   456	            onChange={setCreateValue}
   457	            onSubmit={handleCreateSubmit}
   458	            onCancel={handleCreateCancel}
   459	            level={0}
   460	          />
   461	        )}
   462	        {fileTree.length === 0 && !creating ? (
   463	          <div className="px-4 py-8 text-center text-muted-foreground text-sm">
   464	            {t.file.emptyFolder}
   465	          </div>
   466	        ) : (
   467	          fileTree.map((entry) => (
   468	            <FileTreeItem
   469	              key={entry.path}
   470	              entry={entry}
   471	              currentFile={currentFile}
   472	              selectedPath={selectedPath}
   473	              onSelect={handleSelect}
   474	              onPermanentOpen={handlePermanentOpen}
   475	              onContextMenu={handleContextMenu}
   476	              level={0}
   477	              renamingPath={renamingPath}
   478	              renameValue={renameValue}
   479	              setRenameValue={setRenameValue}
   480	              onRenameSubmit={handleRename}
   481	              onRenameCancel={() => setRenamingPath(null)}
   482	              expandedPaths={expandedPaths}
   483	              toggleExpanded={toggleExpanded}
   484	              creating={creating}
   485	              createValue={createValue}
   486	              setCreateValue={setCreateValue}
   487	              onCreateSubmit={handleCreateSubmit}
   488	              onCreateCancel={handleCreateCancel}
   489	              vaultPath={vaultPath}
   490	            />
   491	          ))
   492	        )}
   493	      </div>
   494	
   495	      {/* Context Menu */}
   496	      {contextMenu && contextMenu.entry && (
   497	        <ContextMenu
   498	          x={contextMenu.x}
   499	          y={contextMenu.y}
   500	          items={getContextMenuItems(contextMenu.entry)}
   501	          onClose={closeContextMenu}
   502	        />
   503	      )}
   504	
   505	      {rootContextMenu && (
   506	        <ContextMenu
   507	          x={rootContextMenu.x}
   508	          y={rootContextMenu.y}
   509	          items={getRootContextMenuItems()}
   510	          onClose={closeContextMenu}
   511	        />
   512	      )}
   513	    </aside>
   514	  );
   515	}
   516	
   517	// ─── CreateInputRow ──────────────────────────────────────────────────────
   518	
   519	interface CreateInputRowProps {
   520	  type: "file" | "folder" | "diagram";
   521	  value: string;
   522	  onChange: (value: string) => void;
   523	  onSubmit: () => void;
   524	  onCancel: () => void;
   525	  level: number;
   526	}
   527	
   528	function CreateInputRow({
   529	  type,
   530	  value,
   531	  onChange,
   532	  onSubmit,
   533	  onCancel,
   534	  level,
   535	}: CreateInputRowProps) {
   536	  const { t } = useLocaleStore();
   537	  const paddingLeft = 12 + level * 16 + 20;
   538	
   539	  const handleKeyDown = (e: React.KeyboardEvent) => {
   540	    if (e.key === "Enter") {
   541	      onSubmit();
   542	    } else if (e.key === "Escape") {
   543	      onCancel();
   544	    }
   545	  };
   546	
   547	  return (
   548	    <div
   549	      data-file-tree-item="true"
   550	      className="w-full flex items-center gap-1.5 py-1.5 pr-2 text-sm rounded-ui-sm"
   551	      style={{ paddingLeft }}
   552	    >
   553	      {type === "folder" ? (
   554	        <Folder className="w-4 h-4 text-muted-foreground shrink-0" />
   555	      ) : type === "diagram" ? (
   556	        <Shapes className="w-4 h-4 text-cyan-500 shrink-0" />
   557	      ) : (
   558	        <File className="w-4 h-4 text-muted-foreground shrink-0" />
   559	      )}
   560	      <input
   561	        type="text"
   562	        value={value}
   563	        onChange={(e) => onChange(e.target.value)}
   564	        onBlur={() => {
   565	          setTimeout(() => {
   566	            if (value.trim()) {
   567	              onSubmit();
   568	            } else {
   569	              onCancel();
   570	            }
   571	          }, 100);
   572	        }}
   573	        onKeyDown={handleKeyDown}
   574	        autoFocus
   575	        placeholder={
   576	          type === "folder"
   577	            ? t.file.folderNamePlaceholder
   578	            : t.file.fileNamePlaceholder
   579	        }
   580	        className="flex-1 ui-input h-6 px-1.5 border-transparent bg-transparent focus-visible:border-primary/40 focus-visible:ring-1 focus-visible:ring-primary/30"
   581	      />
   582	      {type === "file" && (
   583	        <span className="text-muted-foreground text-sm">.md</span>
   584	      )}
   585	      {type === "diagram" && (
   586	        <span className="text-muted-foreground text-sm">.diagram.json</span>
   587	      )}
   588	    </div>
   589	  );
   590	}
   591	
   592	// ─── FileTreeItem ────────────────────────────────────────────────────────
   593	
   594	interface FileTreeItemProps {
   595	  entry: FileEntry;
   596	  currentFile: string | null;
   597	  selectedPath: string | null;
   598	  onSelect: (entry: FileEntry) => void;
   599	  onPermanentOpen: (entry: FileEntry) => void;
   600	  onContextMenu: (e: React.MouseEvent, entry: FileEntry) => void;
   601	  level: number;
   602	  renamingPath: string | null;
   603	  renameValue: string;
   604	  setRenameValue: (value: string) => void;
   605	  onRenameSubmit: () => void;
   606	  onRenameCancel: () => void;
   607	  expandedPaths: Set<string>;
   608	  toggleExpanded: (path: string) => void;
   609	  creating: CreatingState | null;
   610	  createValue: string;
   611	  setCreateValue: (value: string) => void;
   612	  onCreateSubmit: () => void;
   613	  onCreateCancel: () => void;
   614	  vaultPath: string | null;
   615	}
   616	
   617	function FileTreeItem({
   618	  entry,
   619	  currentFile,
   620	  selectedPath,
   621	  onSelect,
   622	  onPermanentOpen,
   623	  onContextMenu,
   624	  level,
   625	  renamingPath,
   626	  renameValue,
   627	  setRenameValue,
   628	  onRenameSubmit,
   629	  onRenameCancel,
   630	  expandedPaths,
   631	  toggleExpanded,
   632	  creating,
   633	  createValue,
   634	  setCreateValue,
   635	  onCreateSubmit,
   636	  onCreateCancel,
   637	  vaultPath,
   638	}: FileTreeItemProps) {
   639	  const [isDragOver, setIsDragOver] = useState(false);
   640	  const { moveFileToFolder, moveFolderToFolder } = useFileStore(
   641	    useShallow((state) => ({
   642	      moveFileToFolder: state.moveFileToFolder,
   643	      moveFolderToFolder: state.moveFolderToFolder,
   644	    })),
   645	  );
   646	
   647	  const isExpanded = expandedPaths.has(entry.path);
   648	  const isActive = currentFile === entry.path;
   649	  const isSelected = selectedPath === entry.path;
   650	  const isRenaming = renamingPath === entry.path;
   651	  const paddingLeft = 12 + level * 16;
   652	
   653	  const selectedIsFile = selectedPath?.toLowerCase().endsWith(".md");
   654	  const showActive =
   655	    (isActive && (!selectedIsFile || selectedPath === currentFile)) ||
   656	    (isSelected && !entry.is_dir);
   657	
   658	  const isCreatingHere = creating && creating.parentPath === entry.path;
   659	
   660	  const handleKeyDown = (e: React.KeyboardEvent) => {
   661	    if (e.key === "Enter") {
   662	      onRenameSubmit();
   663	    } else if (e.key === "Escape") {
   664	      onRenameCancel();
   665	    }
   666	  };
   667	
   668	  const handleFolderMouseDown = (e: React.MouseEvent) => {
   669	    if (e.button !== 0) return;
   670	    setDragData({
   671	      wikiLink: "",
   672	      filePath: entry.path,
   673	      fileName: entry.name,
   674	      isFolder: true,
   675	      startX: e.clientX,
   676	      startY: e.clientY,
   677	      isDragging: false,
   678	    });
   679	  };
   680	
   681	  const handleMouseEnter = useCallback(() => {
   682	    const dragData = getDragData();
   683	    if (dragData?.isDragging && entry.is_dir) {
   684	      if (dragData.filePath === entry.path) return;
   685	      const normalize = (p: string) => p.replace(/\\/g, "/");
   686	      if (
   687	        dragData.isFolder &&
   688	        normalize(entry.path).startsWith(normalize(dragData.filePath) + "/")
   689	      )
   690	        return;
   691	      setIsDragOver(true);
   692	    }
   693	  }, [entry.path, entry.is_dir]);
   694	
   695	  const handleMouseLeave = useCallback(() => {
   696	    setIsDragOver(false);
   697	  }, []);
   698	
   699	  useEffect(() => {
   700	    const handleFolderDrop = async (e: CustomEvent) => {
   701	      if (!isDragOver) return;
   702	      setIsDragOver(false);
   703	
   704	      const { sourcePath, isFolder } = e.detail;
   705	      if (!sourcePath || sourcePath === entry.path) return;
   706	
   707	      try {
   708	        if (isFolder) {
   709	          await moveFolderToFolder(sourcePath, entry.path);
   710	        } else {
   711	          await moveFileToFolder(sourcePath, entry.path);
   712	        }
   713	      } catch {
   714	        // move actions already report failures in useFileStore
   715	      }
   716	    };
   717	
   718	    window.addEventListener(
   719	      "lumina-folder-drop",
   720	      handleFolderDrop as unknown as EventListener,
   721	    );
   722	    return () => {
   723	      window.removeEventListener(
   724	        "lumina-folder-drop",
   725	        handleFolderDrop as unknown as EventListener,
   726	      );
   727	    };
   728	  }, [isDragOver, entry.path, moveFileToFolder, moveFolderToFolder]);
   729	
   730	  if (entry.is_dir) {
   731	    if (isRenaming) {
   732	      return (
   733	        <div
   734	          className="flex items-center gap-1.5 py-1 px-1"
   735	          data-file-tree-item="true"
   736	          style={{ paddingLeft }}
   737	        >
   738	          <ChevronRight className="w-4 h-4 text-muted-foreground shrink-0" />
   739	          <Folder className="w-4 h-4 text-muted-foreground shrink-0" />
   740	          <input
   741	            type="text"
   742	            value={renameValue}
   743	            onChange={(e) => setRenameValue(e.target.value)}
   744	            onBlur={onRenameSubmit}
   745	            onKeyDown={handleKeyDown}
   746	            autoFocus
   747	            className="flex-1 ui-input h-8 px-2 border-primary/60"
   748	          />
   749	        </div>
   750	      );
   751	    }
   752	
   753	    return (
   754	      <div>
   755	        <div
   756	          role="button"
   757	          tabIndex={0}
   758	          data-file-tree-item="true"
   759	          data-folder-path={entry.path}
   760	          onMouseDown={handleFolderMouseDown}
   761	          onClick={() => {
   762	            onSelect(entry);
   763	            toggleExpanded(entry.path);
   764	          }}
   765	          onContextMenu={(e) => onContextMenu(e, entry)}
   766	          onKeyDown={(e) => {
   767	            if (e.key === "Enter") {
   768	              toggleExpanded(entry.path);
   769	            }
   770	          }}
   771	          onMouseEnter={handleMouseEnter}
   772	          onMouseLeave={handleMouseLeave}
   773	          className={cn(
   774	            "w-full flex items-center gap-1.5 py-1.5 pr-2 transition-colors text-sm cursor-pointer select-none rounded-ui-sm",
   775	            isSelected ? "bg-accent/70 text-foreground" : "hover:bg-accent/50",
   776	            isDragOver && "bg-primary/15 ring-1 ring-primary/40 ring-inset",
   777	          )}
   778	          style={{ paddingLeft }}
   779	        >
   780	          {isExpanded ? (
   781	            <ChevronDown className="w-4 h-4 text-muted-foreground shrink-0 pointer-events-none" />
   782	          ) : (
   783	            <ChevronRight className="w-4 h-4 text-muted-foreground shrink-0 pointer-events-none" />
   784	          )}
   785	          {isExpanded ? (
   786	            <FolderOpen className="w-4 h-4 text-amber-500/80 shrink-0 pointer-events-none" />
   787	          ) : (
   788	            <Folder className="w-4 h-4 text-amber-500/70 shrink-0 pointer-events-none" />
   789	          )}
   790	          <span className="truncate pointer-events-none">{entry.name}</span>
   791	        </div>
   792	
   793	        {isExpanded && (
   794	          <div>
   795	            {isCreatingHere && (
   796	              <CreateInputRow
   797	                type={creating.type}
   798	                value={createValue}
   799	                onChange={setCreateValue}
   800	                onSubmit={onCreateSubmit}
   801	                onCancel={onCreateCancel}
   802	                level={level + 1}
   803	              />
   804	            )}
   805	            {entry.children?.map((child) => (
   806	              <FileTreeItem
   807	                key={child.path}
   808	                entry={child}
   809	                currentFile={currentFile}
   810	                selectedPath={selectedPath}
   811	                onSelect={onSelect}
   812	                onPermanentOpen={onPermanentOpen}
   813	                onContextMenu={onContextMenu}
   814	                level={level + 1}
   815	                renamingPath={renamingPath}
   816	                renameValue={renameValue}
   817	                setRenameValue={setRenameValue}
   818	                onRenameSubmit={onRenameSubmit}
   819	                onRenameCancel={onRenameCancel}
   820	                expandedPaths={expandedPaths}
   821	                toggleExpanded={toggleExpanded}
   822	                creating={creating}
   823	                createValue={createValue}
   824	                setCreateValue={setCreateValue}
   825	                onCreateSubmit={onCreateSubmit}
   826	                onCreateCancel={onCreateCancel}
   827	                vaultPath={vaultPath}
   828	              />
   829	            ))}
   830	          </div>
   831	        )}
   832	      </div>
   833	    );
   834	  }
   835	
   836	  // File item with rename support
   837	  if (isRenaming) {
   838	    return (
   839	      <div
   840	        className="flex items-center gap-1.5 py-1 px-1"
   841	        style={{ paddingLeft: paddingLeft + 20 }}
   842	      >
   843	        <File className="w-4 h-4 text-muted-foreground shrink-0" />
   844	        <input
   845	          type="text"
   846	          value={renameValue}
   847	          onChange={(e) => setRenameValue(e.target.value)}
   848	          onBlur={onRenameSubmit}
   849	          onKeyDown={handleKeyDown}
   850	          autoFocus
   851	          className="flex-1 ui-input h-8 px-2 border-primary/60"
   852	        />
   853	        <span className="text-muted-foreground text-sm">.md</span>
   854	      </div>
   855	    );
   856	  }
   857	
   858	  const getFileIcon = () => {
   859	    const name = entry.name.toLowerCase();
   860	    if (name.endsWith(".db.json")) {
   861	      return <File className="w-4 h-4 text-indigo-500 shrink-0" />;
   862	    }
   863	    if (
   864	      name.endsWith(".excalidraw.json") ||
   865	      name.endsWith(".diagram.json") ||
   866	      name.endsWith(".drawio.json")
   867	    ) {
   868	      return <Shapes className="w-4 h-4 text-cyan-500 shrink-0" />;
   869	    }
   870	    if (name.endsWith(".pdf")) {
   871	      return <FileText className="w-4 h-4 text-red-500 shrink-0" />;
   872	    }
   873	    if (
   874	      name.endsWith(".png") ||
   875	      name.endsWith(".jpg") ||
   876	      name.endsWith(".jpeg") ||
   877	      name.endsWith(".gif") ||
   878	      name.endsWith(".webp")
   879	    ) {
   880	      return <Image className="w-4 h-4 text-green-500 shrink-0" />;
   881	    }
   882	    return <File className="w-4 h-4 text-primary/50 shrink-0" />;
   883	  };
   884	
   885	  const handleMouseDown = (e: React.MouseEvent) => {
   886	    if (e.button !== 0) return;
   887	    const linkName = entry.name.replace(/\.(md|db\.json)$/i, "");
   888	    const wikiLink = `[[${linkName}]]`;
   889	    setDragData({
   890	      wikiLink,
   891	      filePath: entry.path,
   892	      fileName: entry.name,
   893	      isFolder: false,
   894	      startX: e.clientX,
   895	      startY: e.clientY,
   896	      isDragging: false,
   897	    });
   898	  };
   899	
   900	  return (
   901	    <div
   902	      data-file-tree-item="true"
   903	      onMouseDown={handleMouseDown}
   904	      onClick={() => onSelect(entry)}
   905	      onDoubleClick={() => onPermanentOpen(entry)}
   906	      onContextMenu={(e) => onContextMenu(e, entry)}
   907	      className={cn(
   908	        "w-full flex items-center gap-1.5 py-1.5 pr-2 transition-colors text-sm cursor-grab select-none rounded-ui-sm border border-transparent",
   909	        showActive
   910	          ? "bg-accent/70 text-foreground font-medium border-border/45"
   911	          : "text-muted-foreground hover:bg-accent/45 hover:text-foreground",
   912	      )}
   913	      style={{ paddingLeft: paddingLeft + 20 }}
   914	    >
   915	      <span className="pointer-events-none">{getFileIcon()}</span>
   916	      <span className="truncate pointer-events-none">
   917	        {getFileName(entry.name)}
   918	      </span>
   919	    </div>
   920	  );
   921	}
