{"content":"     1	import { motion } from "framer-motion";
     2	import { Bot, MessageSquare, Trash2, X } from "lucide-react";
     3	import { useLocaleStore } from "@/stores/useLocaleStore";
     4	import { formatSessionTime } from "./hooks/useSessionManagement";
     5	
     6	type SessionType = "agent" | "chat";
     7	
     8	interface SessionItem {
     9	  id: string;
    10	  title: string;
    11	  updatedAt: number;
    12	  type: SessionType;
    13	}
    14	
    15	interface ChatHistorySidebarProps {
    16	  allSessions: SessionItem[];
    17	  isCurrentSession: (id: string, type: SessionType) => boolean;
    18	  onSwitchSession: (id: string, type: SessionType) => void;
    19	  onDeleteSession: (id: string, type: SessionType) => void;
    20	  onClose: () => void;
    21	}
    22	
    23	export function ChatHistorySidebar({
    24	  allSessions,
    25	  isCurrentSession,
    26	  onSwitchSession,
    27	  onDeleteSession,
    28	  onClose,
    29	}: ChatHistorySidebarProps) {
    30	  const { t } = useLocaleStore();
    31	
    32	  return (
    33	    <>
    34	      {/* Backdrop */}
    35	      <motion.div
    36	        initial={{ opacity: 0 }}
    37	        animate={{ opacity: 1 }}
    38	        exit={{ opacity: 0 }}
    39	        className="absolute inset-0 bg-black/20 z-30"
    40	        onClick={onClose}
    41	      />
    42	      {/* Sidebar panel */}
    43	      <motion.div
    44	        initial={{ x: -240, opacity: 0 }}
    45	        animate={{ x: 0, opacity: 1 }}
    46	        exit={{ x: -240, opacity: 0 }}
    47	        transition={{ duration: 0.2 }}
    48	        className="absolute left-0 top-0 h-full w-60 border-r border-border/60 bg-background shadow-lg z-40 flex flex-col"
    49	      >
    50	        <div className="p-3 border-b border-border/60 flex items-center justify-between">
    51	          <h3 className="text-xs font-medium text-muted-foreground">
    52	            {t.ai.historyChats}
    53	          </h3>
    54	          <button
    55	            onClick={onClose}
    56	            className="p-1 rounded hover:bg-muted text-muted-foreground"
    57	          >
    58	            <X size={12} />
    59	          </button>
    60	        </div>
    61	        <div className="flex-1 overflow-y-auto">
    62	          {allSessions.length === 0 ? (
    63	            <div className="p-4 text-xs text-muted-foreground text-center">
    64	              {t.ai.noHistory}
    65	            </div>
    66	          ) : (
    67	            allSessions.map((session) => {
    68	              const isActive = isCurrentSession(session.id, session.type);
    69	              const IconComponent =
    70	                session.type === "agent"
    71	                  ? Bot
    72	                  : MessageSquare;
    73	              const iconColor =
    74	                session.type === "agent"
    75	                  ? "text-purple-500"
    76	                  : "text-muted-foreground";
    77	
    78	              return (
    79	                <div
    80	                  key={session.id}
    81	                  className={`group flex items-center gap-2 px-3 py-2 cursor-pointer transition-colors ${
    82	                    isActive ? "bg-muted" : "hover:bg-muted/50"
    83	                  }`}
    84	                  onClick={() => onSwitchSession(session.id, session.type)}
    85	                >
    86	                  <IconComponent size={14} className={`shrink-0 ${iconColor}`} />
    87	                  <div className="flex-1 min-w-0">
    88	                    <div className="text-xs font-medium truncate">{session.title}</div>
    89	                    <div className="flex items-center gap-1">
    90	                      {session.type === "agent" && (
    91	                        <span className="text-[9px] text-purple-600 bg-purple-50 dark:bg-purple-900/30 px-1 rounded">
    92	                          Agent
    93	                        </span>
    94	                      )}
    95	                      <span className="text-[10px] text-muted-foreground">
    96	                        {formatSessionTime(session.updatedAt)}
    97	                      </span>
    98	                    </div>
    99	                  </div>
   100	                  <button
   101	                    onClick={(e) => {
   102	                      e.stopPropagation();
   103	                      onDeleteSession(session.id, session.type);
   104	                    }}
   105	                    className="opacity-0 group-hover:opacity-100 p-1 rounded hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-all"
   106	                    title={t.common.delete}
   107	                  >
   108	                    <Trash2 size={12} />
   109	                  </button>
   110	                </div>
   111	              );
   112	            })
   113	          )}
   114	        </div>
   115	      </motion.div>
   116	    </>
   117	  );
   118	}
