{"content":"     1	import { useCallback, useState, useRef } from "react";
     2	import { cn } from "@/lib/utils";
     3	import {
     4	  getResizeHandleIndicatorClassName,
     5	  RESIZE_HANDLE_WRAPPER_CLASSNAME,
     6	} from "./resizeHandleStyles";
     7	
     8	interface ResizeHandleProps {
     9	  direction: "left" | "right";
    10	  onResize: (delta: number) => void;
    11	  onDoubleClick?: () => void;
    12	  className?: string;
    13	}
    14	
    15	const PROXIMITY_MASK =
    16	  "radial-gradient(80px 120px at 50% var(--cursor-y, 50%), black, transparent)";
    17	
    18	export function ResizeHandle({
    19	  direction,
    20	  onResize,
    21	  onDoubleClick,
    22	  className,
    23	}: ResizeHandleProps) {
    24	  const [isDragging, setIsDragging] = useState(false);
    25	  const [isHovering, setIsHovering] = useState(false);
    26	  const indicatorRef = useRef<HTMLDivElement>(null);
    27	  const rafRef = useRef<number | null>(null);
    28	  const lastXRef = useRef(0);
    29	  const latestXRef = useRef(0);
    30	
    31	  const emitResize = useCallback(
    32	    (delta: number) => {
    33	      if (delta === 0) return;
    34	      onResize(direction === "right" ? -delta : delta);
    35	    },
    36	    [direction, onResize]
    37	  );
    38	
    39	  const flushPendingDelta = useCallback(() => {
    40	    const delta = latestXRef.current - lastXRef.current;
    41	    lastXRef.current = latestXRef.current;
    42	    emitResize(delta);
    43	  }, [emitResize]);
    44	
    45	  const handlePointerDown = useCallback(
    46	    (e: React.PointerEvent) => {
    47	      e.preventDefault();
    48	      e.stopPropagation();
    49	      e.currentTarget.setPointerCapture(e.pointerId);
    50	      lastXRef.current = e.clientX;
    51	      latestXRef.current = e.clientX;
    52	      setIsDragging(true);
    53	
    54	      // 拖动时禁用侧边栏的过渡动画
    55	      document.body.classList.add("resizing");
    56	    },
    57	    []
    58	  );
    59	
    60	  const handlePointerMove = useCallback(
    61	    (e: React.PointerEvent) => {
    62	      // Track cursor Y for proximity mask (works during both hover and drag)
    63	      if (indicatorRef.current) {
    64	        const rect = indicatorRef.current.getBoundingClientRect();
    65	        indicatorRef.current.style.setProperty(
    66	          "--cursor-y",
    67	          `${e.clientY - rect.top}px`
    68	        );
    69	      }
    70	
    71	      // Only process resize when pointer is captured (dragging)
    72	      if (!e.currentTarget.hasPointerCapture(e.pointerId)) return;
    73	
    74	      latestXRef.current = e.clientX;
    75	
    76	      // 使用 requestAnimationFrame 节流，并始终消费最新坐标，避免帧内丢增量
    77	      if (rafRef.current) return;
    78	
    79	      rafRef.current = requestAnimationFrame(() => {
    80	        flushPendingDelta();
    81	        rafRef.current = null;
    82	      });
    83	    },
    84	    [flushPendingDelta]
    85	  );
    86	
    87	  const handlePointerUp = useCallback(
    88	    (e: React.PointerEvent) => {
    89	      if (!e.currentTarget.hasPointerCapture(e.pointerId)) return;
    90	
    91	      setIsDragging(false);
    92	      if (rafRef.current) {
    93	        cancelAnimationFrame(rafRef.current);
    94	        rafRef.current = null;
    95	        flushPendingDelta();
    96	      }
    97	      lastXRef.current = 0;
    98	      latestXRef.current = 0;
    99	      // 恢复过渡动画
   100	      document.body.classList.remove("resizing");
   101	    },
   102	    [flushPendingDelta]
   103	  );
   104	
   105	  const hitAreaStyle =
   106	    direction === "left"
   107	      ? { left: "-1px", right: "-7px" }
   108	      : { left: "-1px", right: "-7px" };
   109	
   110	  // Hover: proximity mask around cursor; Drag: full glow, stronger intensity
   111	  const indicatorStyle: React.CSSProperties | undefined =
   112	    isDragging
   113	      ? {
   114	          backgroundColor: "hsl(var(--border) / 0.3)",
   115	          boxShadow: "0 0 7px hsl(var(--border) / 0.35)",
   116	        }
   117	      : isHovering
   118	        ? { maskImage: PROXIMITY_MASK, WebkitMaskImage: PROXIMITY_MASK }
   119	        : undefined;
   120	
   121	  return (
   122	    <div
   123	      className={cn(
   124	        RESIZE_HANDLE_WRAPPER_CLASSNAME,
   125	        className
   126	      )}
   127	    >
   128	      <div
   129	        ref={indicatorRef}
   130	        className={getResizeHandleIndicatorClassName(isDragging || isHovering, direction)}
   131	        style={indicatorStyle}
   132	      />
   133	
   134	      {/* Clickable area - 这是实际的点击区域 */}
   135	      <div
   136	        className="absolute inset-y-0 cursor-col-resize z-30 touch-none"
   137	        style={hitAreaStyle}
   138	        onPointerDown={handlePointerDown}
   139	        onPointerMove={handlePointerMove}
   140	        onPointerUp={handlePointerUp}
   141	        onLostPointerCapture={() => {
   142	          if (isDragging) {
   143	            setIsDragging(false);
   144	            if (rafRef.current) {
   145	              cancelAnimationFrame(rafRef.current);
   146	              rafRef.current = null;
   147	              flushPendingDelta();
   148	            }
   149	            lastXRef.current = 0;
   150	            latestXRef.current = 0;
   151	            document.body.classList.remove("resizing");
   152	          }
   153	        }}
   154	        onDoubleClick={onDoubleClick}
   155	        onPointerEnter={() => setIsHovering(true)}
   156	        onPointerLeave={() => setIsHovering(false)}
   157	      />
   158	    </div>
   159	  );
   160	}
